  method: 'GET',
  url: 'https://api.close.com/api/v1/opportunity/?lead_id=' + input.leadId + '&status_type=active&_limit=1&_order_by=-date_created',
  headers: { 'Authorization': CLOSE_AUTH, 'Accept': 'application/json' }
});

const opportunities = oppResp.data || [];
let oppResult;

if (opportunities.length > 0) {
  const opp = opportunities[0];
  const updateBody = { close_date: input.closeDateStr };
  if (input.targetOppStatus) {
    updateBody.status_id = input.targetOppStatus;
  }
  oppResult = await this.helpers.httpRequest({
    method: 'PUT',
    url: 'https://api.close.com/api/v1/opportunity/' + opp.id,
    headers: { 'Authorization': CLOSE_AUTH, 'Content-Type': 'application/json' },
