const driveItems = $input.all();

const transcripts = [];
for (let i = 0; i < transcribeItems.length; i++) {
  const orig = transcribeItems[i].json;
  const drive = driveItems[i]?.json || {};

  if (!orig.source_type || !orig.content) continue;

  const t = {
    source_type: orig.source_type,
    source_id: orig.source_id,
    close_call_id: orig.close_call_id || null,
    lead_id: orig.lead_id,
    owner_id: orig.owner_id || null,
    content: orig.content,
    recording_url: orig.recording_url || '',
    call_type: orig.call_type,
    synced_at: orig.synced_at
  };

  if (drive.id && drive.mimeType) {
    t.google_drive_file_id = drive.id;
    t.google_drive_url = drive.webViewLink || '';
  }
  transcripts.push(t);
}

return [{ json: { transcripts, skippedCalls: [], count: transcripts.length } }];

