    totalCalls: calls.length
  }
}));

// Recording-URL aufloesen (Close 302 → S3 Direct Link)
const item = $json;
const CLOSE_AUTH = 'Basic YXBpXzJKd0JqaHMwYmZCUmJ5d3dHeXA0blUuMWlWV0NZVUUyRzE3NWh6NjJmNEJMRzo=';

let downloadUrl = item.recordingUrl;

try {
  const headResp = await this.helpers.httpRequest({
    method: 'HEAD',
    url: item.recordingUrl,
    headers: { 'Authorization': CLOSE_AUTH },
    disableFollowRedirect: true,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true
  });
  const loc = (headResp.headers || {}).location || (headResp.headers || {}).Location;
  if (loc) downloadUrl = loc;
} catch (headErr) {
  const errHeaders = headErr?.response?.headers || headErr?.cause?.response?.headers || {};
  const loc = errHeaders.location || errHeaders.Location;
  if (loc) downloadUrl = loc;
}

return [{
  json: {
    ...item,
    directUrl: downloadUrl,
    _fileName: 'call_' + item.closeCallId.substring(5, 20) + '_' + new Date().toISOString().substring(0, 10) + '.mp3'
  }
}];

// Ergebnisse nach dem Loop sammeln
const items = $input.all();
const transcripts = [];
const skippedCalls = [];
let totalSkipped = [];

for (const item of items) {
  const j = item.json;
  if (j._skipped) {
    skippedCalls.push({ id: j.closeCallId, reason: j._reason, message: j._message || '' });
    continue;
  }
  if (j.source_type === 'call') {
    transcripts.push(j);
  }
  if (j.skippedCalls) totalSkipped = j.skippedCalls;
}

if (transcripts.length === 0) {
  return [{ json: { transcripts: [], skippedCalls: [...totalSkipped, ...skippedCalls], count: 0 } }];
}

// Items mit Binary-Daten durchreichen fuer Google Drive
const output = [];
for (const item of items) {
  if (!item.json._skipped && item.json.source_type === 'call') {
    output.push({
      json: { ...item.json, skippedCalls: [...totalSkipped, ...skippedCalls], count: transcripts.length },
      binary: item.binary || {}
    });
  }
}
return output;

// Transcript-Objekt bauen aus Whisper-Ergebnis + Metadaten
const meta = $('Resolve Recording URL').first().json;
const whisperResult = $json;

const transcriptText = whisperResult.text || '';

if (!transcriptText) {
  return [{ json: { _skipped: true, _reason: 'no_transcript', closeCallId: meta.closeCallId } }];
}

// Neue UUID als source_id generieren (Supabase erwartet UUID-Format)
function uuid() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, c => {
    const r = Math.random() * 16 | 0;
    return (c === 'x' ? r : (r & 0x3 | 0x8)).toString(16);
  });
}

return [{
  json: {
    source_type: 'call',
    source_id: uuid(),
    close_call_id: meta.closeCallId,
    lead_id: meta.leadUuid || null,
    owner_id: meta.ownerUuid || null,
    content: transcriptText,
    recording_url: meta.recordingUrl || '',
    call_type: 'erstgespraech',
    synced_at: new Date().toISOString(),
    _fileName: meta._fileName,
    _skipped: false,
    count: 1
  },
  binary: $('Download Audio').first().binary || {}
}];
